document.addEventListener("DOMContentLoaded",()=>{const themeToggle=document.getElementById("themeToggle");const htmlElement=document.documentElement;const savedTheme=localStorage.getItem("theme");const prefersDark=window.matchMedia("(prefers-color-scheme: dark)").matches;if(savedTheme==="dark"||!savedTheme&&prefersDark){htmlElement.setAttribute("data-theme","dark")}themeToggle.addEventListener("click",()=>{const currentTheme=htmlElement.getAttribute("data-theme");const newTheme=currentTheme==="dark"?"light":"dark";if(newTheme==="dark"){htmlElement.setAttribute("data-theme","dark");localStorage.setItem("theme","dark")}else{htmlElement.removeAttribute("data-theme");localStorage.setItem("theme","light")}});const header=document.querySelector(".header");window.addEventListener("scroll",()=>{if(window.scrollY>20){header.classList.add("scrolled")}else{header.classList.remove("scrolled")}});const revealElements=document.querySelectorAll(".reveal-elem, .hero-reveal");const revealObserver=new IntersectionObserver((entries,observer)=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add("revealed");observer.unobserve(entry.target)}})},{threshold:.1,rootMargin:"0px 0px -40px 0px"});revealElements.forEach(el=>{revealObserver.observe(el)});const statsElements=document.querySelectorAll(".stat-value");let animationTriggered=false;const animateStats=()=>{if(animationTriggered)return;animationTriggered=true;statsElements.forEach(stat=>{const targetText=stat.innerText;const match=targetText.match(/([^\d]*)([\d,]+)([^\d]*)/);if(!match)return;const prefix=match[1]||"";let targetNumberStr=match[2].replace(/,/g,"");const suffix=match[3]||"";const isFloat=targetNumberStr.includes(".");const targetNumber=isFloat?parseFloat(targetNumberStr):parseInt(targetNumberStr,10);if(isNaN(targetNumber))return;const duration=2e3;const frameRate=30;const totalFrames=Math.round(duration/(1e3/frameRate));const increment=targetNumber/totalFrames;let currentNumber=0;let frame=0;const timer=setInterval(()=>{frame++;currentNumber+=increment;let displayValue="";if(frame>=totalFrames||currentNumber>=targetNumber){clearInterval(timer);currentNumber=targetNumber}if(isFloat){const decimals=targetNumberStr.split(".")[1]?.length||1;displayValue=currentNumber.toFixed(decimals)}else{displayValue=Math.round(currentNumber).toString()}stat.innerText=`${prefix}${displayValue}${suffix}`},1e3/frameRate)})};const statsSection=document.querySelector(".hero-stats");if(statsSection){const statsObserver=new IntersectionObserver(entries=>{if(entries[0].isIntersecting){animateStats();statsObserver.unobserve(statsSection)}},{threshold:.5});statsObserver.observe(statsSection)}const particlesContainer=document.getElementById("particles-container");if(particlesContainer){const particleCount=65;for(let i=0;i<particleCount;i++){const particle=document.createElement("div");particle.classList.add("particle");const left=Math.random()*100;const width=Math.random()*5+2;const duration=Math.random()*15+15;const delay=-(Math.random()*duration);const maxOpacity=Math.random()*.3+.1;particle.style.left=`${left}%`;particle.style.width=`${width}px`;particle.style.height=`${width}px`;particle.style.animationDelay=`${delay}s`;particle.style.setProperty("--duration",`${duration}s`);particle.style.setProperty("--max-opacity",maxOpacity);particle.style.setProperty("--width",`${width}px`);const colorTypeIndex=Math.floor(Math.random()*3);particle.setAttribute("data-color-type",colorTypeIndex);particlesContainer.appendChild(particle)}}document.querySelectorAll('a[href^="#"]').forEach(anchor=>{anchor.addEventListener("click",function(e){e.preventDefault();const targetId=this.getAttribute("href");if(targetId==="#")return;const targetElement=document.querySelector(targetId);if(targetElement){targetElement.scrollIntoView({behavior:"smooth"})}})});const hamburgerBtn=document.getElementById("hamburgerBtn");const mobileNav=document.getElementById("mobileNav");if(hamburgerBtn&&mobileNav){hamburgerBtn.addEventListener("click",()=>{hamburgerBtn.classList.toggle("active");mobileNav.classList.toggle("open")});mobileNav.querySelectorAll("a").forEach(link=>{link.addEventListener("click",()=>{hamburgerBtn.classList.remove("active");mobileNav.classList.remove("open")})})}const conn=navigator.connection||navigator.mozConnection||navigator.webkitConnection;const effectiveType=conn?conn.effectiveType:null;const saveData=conn?conn.saveData:false;if(saveData||effectiveType==="slow-2g"||effectiveType==="2g"){document.querySelectorAll(".gallery-item img[srcset]").forEach(img=>{img.srcset=img.srcset.split(",").find(s=>s.includes("_800w"))||img.srcset})}else if(effectiveType==="3g"){document.querySelectorAll(".gallery-item img[srcset]").forEach(img=>{img.srcset=img.srcset.split(",").filter(s=>!s.includes("2000w")).join(",")})}const reviewsMarquee=document.querySelector(".reviews-marquee");const reviewsTrack=document.querySelector(".reviews-track");if(reviewsMarquee&&reviewsTrack){const DURATION=40;let isDown=false,startX=0,currentX=0,animationOffset=0;const getTranslateX=()=>new DOMMatrix(window.getComputedStyle(reviewsTrack).transform).m41;const startDrag=x=>{isDown=true;startX=x;animationOffset=getTranslateX();reviewsTrack.style.animationPlayState="paused";reviewsTrack.style.transform="translateX("+animationOffset+"px)";reviewsMarquee.style.cursor="grabbing"};const moveDrag=x=>{if(!isDown)return;currentX=animationOffset+(x-startX);reviewsTrack.style.transform="translateX("+currentX+"px)"};const endDrag=()=>{if(!isDown)return;isDown=false;reviewsMarquee.style.cursor="grab";const halfWidth=reviewsTrack.scrollWidth/2;let norm=currentX%halfWidth;if(norm>0)norm-=halfWidth;const delay=-(Math.abs(norm)/halfWidth)*DURATION;reviewsTrack.style.transform="";reviewsTrack.style.animationDelay=delay+"s";reviewsTrack.style.animationPlayState="running"};reviewsMarquee.addEventListener("mousedown",e=>{e.preventDefault();startDrag(e.pageX)});window.addEventListener("mousemove",e=>moveDrag(e.pageX));window.addEventListener("mouseup",endDrag);reviewsMarquee.addEventListener("touchstart",e=>startDrag(e.touches[0].pageX),{passive:true});reviewsMarquee.addEventListener("touchmove",e=>{moveDrag(e.touches[0].pageX);e.preventDefault()},{passive:false});reviewsMarquee.addEventListener("touchend",endDrag);reviewsMarquee.style.cursor="grab"}const sections=document.querySelectorAll("section[id]");const navLinks=document.querySelectorAll(".nav-links a");const observerOptions={threshold:.2,rootMargin:"-10% 0px -40% 0px"};const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting){const id=entry.target.getAttribute("id");navLinks.forEach(link=>{link.classList.toggle("active",link.getAttribute("href")==="#"+id)})}})},observerOptions);sections.forEach(section=>observer.observe(section))});